module top_module(
    input               clk,
    input               load,
    input       [1:0]   ena,
    input       [99:0]  data,
    output  reg [99:0]  q
);reg         [99:0]  shifted_output;
    always @(posedge clk) begin
            q <= shifted_output;
    end

    always @(*) begin
        if (load)
            shifted_output = data;
        else
            case (ena)
            2'b01   : shifted_output = {q[0], q[99:1]};
            2'b10   : shifted_output = {q[98:0], q[99]};
            default : shifted_output = q;
            endcase
    end

endmodule
